import { 
  Appointment, 
  AppointmentStatus, 
  ConsultationType, 
  ApiResponse, 
  PaginatedResponse,
  TimeSlot 
} from '@/types';
import { mockAppointments, mockDoctors, mockPatients } from '@/data/mockData';
import { apiSuccess, apiError, paginatedSuccess } from './api';

// In-memory store for appointments (simulating database)
let appointments = [...mockAppointments];

export interface CreateAppointmentData {
  patientId: string;
  doctorId: string;
  date: string;
  time: string;
  type: ConsultationType;
  symptoms?: string;
}

export const appointmentService = {
  async getAppointments(
    filters?: {
      patientId?: string;
      doctorId?: string;
      status?: AppointmentStatus;
      type?: ConsultationType;
      date?: string;
    },
    page: number = 1,
    limit: number = 10
  ): Promise<PaginatedResponse<Appointment>> {
    let filtered = [...appointments];

    if (filters?.patientId) {
      filtered = filtered.filter(a => a.patientId === filters.patientId);
    }
    if (filters?.doctorId) {
      filtered = filtered.filter(a => a.doctorId === filters.doctorId);
    }
    if (filters?.status) {
      filtered = filtered.filter(a => a.status === filters.status);
    }
    if (filters?.type) {
      filtered = filtered.filter(a => a.type === filters.type);
    }
    if (filters?.date) {
      filtered = filtered.filter(a => a.date === filters.date);
    }

    // Add patient and doctor info
    const enriched = filtered.map(apt => ({
      ...apt,
      patient: mockPatients.find(p => p.id === apt.patientId),
      doctor: mockDoctors.find(d => d.id === apt.doctorId),
    }));

    // Sort by date (newest first)
    enriched.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    const start = (page - 1) * limit;
    const paginatedData = enriched.slice(start, start + limit);

    return paginatedSuccess(paginatedData, page, limit, enriched.length);
  },

  async getAppointmentById(id: string): Promise<ApiResponse<Appointment | null>> {
    const appointment = appointments.find(a => a.id === id);
    if (!appointment) {
      return apiError('Appointment not found');
    }

    const enriched = {
      ...appointment,
      patient: mockPatients.find(p => p.id === appointment.patientId),
      doctor: mockDoctors.find(d => d.id === appointment.doctorId),
    };

    return apiSuccess(enriched);
  },

  async createAppointment(data: CreateAppointmentData): Promise<ApiResponse<Appointment>> {
    const doctor = mockDoctors.find(d => d.id === data.doctorId);
    if (!doctor) {
      return apiError('Doctor not found');
    }

    const newAppointment: Appointment = {
      id: `apt-${Date.now()}`,
      ...data,
      status: 'pending',
      paymentStatus: 'pending',
      queueNumber: appointments.filter(a => a.doctorId === data.doctorId && a.date === data.date).length + 1,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    appointments.push(newAppointment);
    
    return apiSuccess(
      {
        ...newAppointment,
        doctor,
        patient: mockPatients.find(p => p.id === data.patientId),
      },
      'Appointment booked successfully'
    );
  },

  async updateAppointmentStatus(
    id: string, 
    status: AppointmentStatus,
    notes?: string
  ): Promise<ApiResponse<Appointment>> {
    const index = appointments.findIndex(a => a.id === id);
    if (index === -1) {
      return apiError('Appointment not found');
    }

    appointments[index] = {
      ...appointments[index],
      status,
      notes: notes || appointments[index].notes,
      updatedAt: new Date().toISOString(),
    };

    return apiSuccess(appointments[index], `Appointment ${status}`);
  },

  async cancelAppointment(id: string): Promise<ApiResponse<Appointment>> {
    return this.updateAppointmentStatus(id, 'cancelled');
  },

  async rescheduleAppointment(
    id: string,
    newDate: string,
    newTime: string
  ): Promise<ApiResponse<Appointment>> {
    const index = appointments.findIndex(a => a.id === id);
    if (index === -1) {
      return apiError('Appointment not found');
    }

    appointments[index] = {
      ...appointments[index],
      date: newDate,
      time: newTime,
      updatedAt: new Date().toISOString(),
    };

    return apiSuccess(appointments[index], 'Appointment rescheduled');
  },

  async getQueuePosition(appointmentId: string): Promise<ApiResponse<{ position: number; total: number }>> {
    const appointment = appointments.find(a => a.id === appointmentId);
    if (!appointment) {
      return apiError('Appointment not found');
    }

    const sameQueue = appointments.filter(
      a => a.doctorId === appointment.doctorId && 
           a.date === appointment.date && 
           ['confirmed', 'in-progress'].includes(a.status)
    );

    const position = sameQueue.findIndex(a => a.id === appointmentId) + 1;

    return apiSuccess({ position, total: sameQueue.length });
  },

  async getAvailableSlots(
    doctorId: string,
    date: string
  ): Promise<ApiResponse<TimeSlot[]>> {
    // Generate time slots (9 AM to 5 PM, 30-minute intervals)
    const slots: TimeSlot[] = [];
    const bookedTimes = appointments
      .filter(a => a.doctorId === doctorId && a.date === date && a.status !== 'cancelled')
      .map(a => a.time);

    for (let hour = 9; hour < 17; hour++) {
      for (let min = 0; min < 60; min += 30) {
        const time = `${hour.toString().padStart(2, '0')}:${min.toString().padStart(2, '0')}`;
        slots.push({
          id: `slot-${date}-${time}`,
          date,
          startTime: time,
          endTime: `${hour}:${min + 30 === 60 ? '00' : (min + 30).toString().padStart(2, '0')}`,
          isAvailable: !bookedTimes.includes(time),
        });
      }
    }

    return apiSuccess(slots);
  },

  async getTodayQueue(doctorId: string): Promise<ApiResponse<Appointment[]>> {
    const today = new Date().toISOString().split('T')[0];
    const queue = appointments
      .filter(
        a => a.doctorId === doctorId && 
             a.date === today && 
             ['confirmed', 'in-progress'].includes(a.status)
      )
      .map(apt => ({
        ...apt,
        patient: mockPatients.find(p => p.id === apt.patientId),
      }))
      .sort((a, b) => (a.queueNumber || 0) - (b.queueNumber || 0));

    return apiSuccess(queue);
  },
};
