import { Doctor, ApiResponse, PaginatedResponse } from '@/types';
import { mockDoctors } from '@/data/mockData';
import { apiSuccess, paginatedSuccess } from './api';

export interface DoctorSearchFilters {
  specialty?: string;
  location?: string;
  name?: string;
  isAvailable?: boolean;
  minRating?: number;
  maxFee?: number;
}

export const doctorService = {
  async getDoctors(
    filters?: DoctorSearchFilters,
    page: number = 1,
    limit: number = 10
  ): Promise<PaginatedResponse<Doctor>> {
    let filtered = [...mockDoctors];

    if (filters?.specialty) {
      filtered = filtered.filter(d => 
        d.specialty.toLowerCase().includes(filters.specialty!.toLowerCase()) ||
        d.specialties.some(s => s.toLowerCase().includes(filters.specialty!.toLowerCase()))
      );
    }
    if (filters?.location) {
      filtered = filtered.filter(d => 
        d.location.toLowerCase().includes(filters.location!.toLowerCase())
      );
    }
    if (filters?.name) {
      filtered = filtered.filter(d => 
        d.name.toLowerCase().includes(filters.name!.toLowerCase())
      );
    }
    if (filters?.isAvailable !== undefined) {
      filtered = filtered.filter(d => d.isAvailable === filters.isAvailable);
    }
    if (filters?.minRating) {
      filtered = filtered.filter(d => d.rating >= filters.minRating!);
    }
    if (filters?.maxFee) {
      filtered = filtered.filter(d => d.consultationFee <= filters.maxFee!);
    }

    // Sort by rating (highest first)
    filtered.sort((a, b) => b.rating - a.rating);

    const start = (page - 1) * limit;
    const paginatedData = filtered.slice(start, start + limit);

    return paginatedSuccess(paginatedData, page, limit, filtered.length);
  },

  async getDoctorById(id: string): Promise<ApiResponse<Doctor | null>> {
    const doctor = mockDoctors.find(d => d.id === id);
    return apiSuccess(doctor || null);
  },

  async getTopDoctors(limit: number = 5): Promise<ApiResponse<Doctor[]>> {
    const top = [...mockDoctors]
      .sort((a, b) => b.rating - a.rating)
      .slice(0, limit);
    
    return apiSuccess(top);
  },

  async getDoctorsBySpecialty(specialty: string): Promise<ApiResponse<Doctor[]>> {
    const doctors = mockDoctors.filter(d => 
      d.specialty.toLowerCase() === specialty.toLowerCase() ||
      d.specialties.some(s => s.toLowerCase() === specialty.toLowerCase())
    );
    
    return apiSuccess(doctors);
  },

  async updateAvailability(doctorId: string, isAvailable: boolean): Promise<ApiResponse<Doctor>> {
    const doctor = mockDoctors.find(d => d.id === doctorId);
    if (!doctor) {
      return apiSuccess(null as unknown as Doctor);
    }

    doctor.isAvailable = isAvailable;
    return apiSuccess(doctor, 'Availability updated');
  },

  async updateOnDemand(doctorId: string, isOnDemand: boolean): Promise<ApiResponse<Doctor>> {
    const doctor = mockDoctors.find(d => d.id === doctorId);
    if (!doctor) {
      return apiSuccess(null as unknown as Doctor);
    }

    doctor.isOnDemand = isOnDemand;
    return apiSuccess(doctor, 'On-demand status updated');
  },

  async updateProfile(doctorId: string, data: Partial<Doctor>): Promise<ApiResponse<Doctor>> {
    const doctor = mockDoctors.find(d => d.id === doctorId);
    if (!doctor) {
      return apiSuccess(null as unknown as Doctor);
    }

    Object.assign(doctor, data);
    return apiSuccess(doctor, 'Profile updated');
  },
};
